let itemsRaw = $input.all().map(i => i.json);

// Si por alguna razón n8n agrupa la respuesta en array, lo desempaquetamos
if(itemsRaw.length === 1 && Array.isArray(itemsRaw[0])) {
  itemsRaw = itemsRaw[0];
}

// solo reels (videos)
const reels = itemsRaw.filter(p => p.type === "Video" && p.videoUrl);

// calcular score viral
const sorted = reels
  .map(p => ({
    ...p,
    viralScore: (
      (p.videoViewCount || 0) * 0.6 +
      (p.likesCount || 0) * 0.3 +
      (p.commentsCount || 0) * 0.1
    )
  }))
  .sort((a, b) => b.viralScore - a.viralScore)
  .slice(0, 5); // top 5

return sorted.map(r => ({ json: r }));

const combined = $input.all().map((i, index) => {
  let transcript = 'Sin texto reconocido';
  if (i.json.text) transcript = i.json.text;

  return `--- VIDEO VIRAL ${index + 1} --->\n` +
         `URL Original: ${i.json.videoUrl}\n` +
         `Vistas: ${i.json.videoViewCount}\n` +
         `Likes: ${i.json.likesCount}\n` +
         `Score Viral: ${i.json.viralScore}\n` +
         `TEXTO HABLADO COPIADO DE SU VOZ: \"${transcript}\"\n`;
}).join("\n\n");

return { json: { corpus: combined } };

for (const item of $input.all()) {
  if (item.binary && item.binary.data) {
    item.binary.data.fileName = 'video.mp4';
    item.binary.data.mimeType = 'video/mp4';
    item.binary.data.fileExtension = 'mp4';
  }
}
return $input.all();

// Extraemos la lista de ideas directamente de la respuesta de OpenAI
const ideas = $input.all()[0].json.message.content.ideas;

// Devolvemos un único objeto con la lista limpia
return {
  ideas: ideas
};

