// 1. Buscamos los datos de forma flexible (no importa el nombre del nodo anterior)
const data = $input.all()[0].json;

// 2. Intentamos encontrar la URL en cualquier formato que PDFMonkey decida enviarla
const doc = data.document_card || data.document || data;
const rawUrl = doc.download_url || (data.documents && data.documents[0] ? data.documents[0].download_url : null);

if (!rawUrl) {
  throw new Error("No se encontró la URL del PDF. Revisa la salida del nodo anterior.");
}

// 3. Limpiamos solo lo necesario
const cleanUrl = rawUrl.split('?')[0];

return {
  pdfUrl: cleanUrl,
  documentId: doc.id || data.id
};
